// Test stale strategy with TTL
task compute_stale {
    params: {
        value: int
    }
    inputs: []
    cache: {
        enabled: true
        strategy: "stale"
        ttl: {
            seconds: 2
        }
    }
    run: {
        echo "Computing with stale strategy for ${params.value}";
        echo $((${params.value} + 100)) > result.txt;
    }
    output: "stale_${params.value}"
}

task runner {
    requires: {
        compute_stale(5);
    }
    run: {
        echo "Done";
    }
    output: "runner_out"
}

