// Test key_include/key_exclude and version
task selective_cache {
    params: {
        important: int
        unimportant: string
    }
    inputs: []
    cache: {
        enabled: true
        strategy: "content"
        version: "v1"
        key: {
            include: ["important"]
        }
    }
    run: {
        echo "important=${params.important} unimportant=${params.unimportant}";
    }
    output: "selective_${params.important}"
}

task selective_runner {
    requires: {
        selective_cache(important=10, unimportant="a");
        selective_cache(important=10, unimportant="b");  // Should hit cache - same 'important', 'unimportant' is excluded
        selective_cache(important=20, unimportant="a");  // Miss - different 'important'
    }
    run: {
        echo "Done";
    }
    output: "selective_runner_out"
}

